// â”€â”€â”€ Cash Flow â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
export function downloadCashFlowPdf(data: any) {
  const doc = new jsPDF("p", "mm", "a4");
  const w = doc.internal.pageSize.getWidth();
  let y = addHeader(doc, "Cash Flow Report", "12-month disbursement vs collection");

  doc.setFillColor(LIGHT_BG);
  doc.roundedRect(14, y, w - 28, 14, 2, 2, "F");
  kv(doc, "Total Disbursed:", kes(data.totalDisbursed), 20, y + 8, 40);
  kv(doc, "Total Collected:", kes(data.totalCollected), w / 2 + 6, y + 8, 40);
  y += 20;

  autoTable(doc, {
    startY: y,
    head: [["Month", "Disbursed (KES)", "Collected (KES)", "Net Flow (KES)"]],
    body: (data.months ?? []).map((m: any) => [
      m.label,
      kes(m.disbursed),
      kes(m.collected),
      (m.netFlow >= 0 ? "+" : "") + kes(m.netFlow),
    ]),
    foot: [["Total", kes(data.totalDisbursed), kes(data.totalCollected),
      (data.netCashFlow >= 0 ? "+" : "") + kes(data.netCashFlow)]],
    footStyles: { fontStyle: "bold", fillColor: "#e5e7eb" as any },
    ...TABLE_STYLES,
  });

  addFooters(doc);
  doc.save(`cashflow-report-${today()}.pdf`);
}

