// â”€â”€â”€ Monthly Snapshot â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
export function downloadMonthlyReportPdf(data: any) {
  const doc = new jsPDF("l", "mm", "a4"); // landscape
  const w = doc.internal.pageSize.getWidth();
  let y = addHeader(doc, `Monthly Portfolio Report â€” ${data.periodLabel}`,
    `Generated ${new Date(data.generatedAt).toLocaleString("en-KE")} by ${data.generatedBy || "System"}`);

  // Accounting summary box
  doc.setFillColor(LIGHT_BG);
  doc.roundedRect(14, y, w - 28, 36, 2, 2, "F");
  kv(doc, "Opening Balance:",       kes(data.openingPortfolioBalance),  20, y + 7, 45);
  kv(doc, "+ New Loans Disbursed:", kes(data.newLoansDisbursed),        20, y + 14, 45);
  kv(doc, "+ Penalties:",           kes(data.totalPenaltiesCharged),    20, y + 21, 45);
  kv(doc, "âˆ’ Repayments:",          kes(data.totalRepaymentsCollected), 20, y + 28, 45);
  kv(doc, "= Closing Balance:",     kes(data.closingPortfolioBalance),  w / 2 + 6, y + 7, 45);
  kv(doc, "Expected Collections:",  kes(data.expectedCollections),      w / 2 + 6, y + 14, 45);
  kv(doc, "Actual Collections:",    kes(data.actualCollections),        w / 2 + 6, y + 21, 45);
  kv(doc, "Collection Rate:",       `${data.collectionRate}%`,          w / 2 + 6, y + 28, 45);
  y += 42;

  autoTable(doc, {
    startY: y,
    head: [["Client", "Type", "Disbursed", "Opening Bal.", "New Loan", "Paid", "Penalties", "Closing Bal.", "Status", "DPD"]],
    body: (data.entries ?? []).map((e: any) => [
      e.clientName, e.loanType,
      e.disbursementDate ? new Date(e.disbursementDate).toLocaleDateString("en-KE") : "â€”",
      kes(e.openingBalance), e.newLoanAmount > 0 ? kes(e.newLoanAmount) : "â€”",
      e.amountPaidThisMonth > 0 ? kes(e.amountPaidThisMonth) : "â€”",
      e.penaltiesThisMonth > 0 ? kes(e.penaltiesThisMonth) : "â€”",
      kes(e.closingBalance), e.loanStatus,
      e.daysPastDue > 0 ? String(e.daysPastDue) : "â€”",
    ]),
    foot: [["Period Totals", "", "",
      kes(data.openingPortfolioBalance), kes(data.newLoansDisbursed),
      kes(data.totalRepaymentsCollected), kes(data.totalPenaltiesCharged),
      kes(data.closingPortfolioBalance), "", ""]],
    footStyles: { fontStyle: "bold", fillColor: "#e5e7eb" as any },
    ...TABLE_STYLES,
    styles: { fontSize: 7.5 },
  });

  addFooters(doc);
  doc.save(`monthly-report-${data.year}-${String(data.month).padStart(2, "0")}.pdf`);
}

// â”€â”€â”€ Loan Statement â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
export function downloadLoanStatementPdf(data: any) {
  const doc = new jsPDF("p", "mm", "a4");
  const w = doc.internal.pageSize.getWidth();
  const { loan, repayments, penalties, summary } = data;

  // Header
  doc.setFillColor(PRIMARY);
  doc.rect(0, 0, w, 22, "F");
  doc.setTextColor(255, 255, 255);
  doc.setFont("helvetica", "bold");
  doc.setFontSize(14);
  doc.text("El Elyon Capital", 14, 10);
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8);
  doc.text("Capital & Credit Solutions", 14, 17);
  doc.setFont("helvetica", "bold");
  doc.setFontSize(14);
  doc.text("LOAN STATEMENT", w - 14, 10, { align: "right" });
  doc.setFont("helvetica", "normal");
  doc.setFontSize(8);
  doc.text(`Loan ID: ${loan.id?.slice(-12).toUpperCase()}`, w - 14, 17, { align: "right" });

  let y = 30;

  // Borrower + Loan info side by side
  doc.setFillColor(LIGHT_BG);
  const boxWidth = (w - 28) / 2 - 3;
  doc.roundedRect(14, y, boxWidth, 42, 2, 2, "F");
  doc.roundedRect(14 + boxWidth + 6, y, boxWidth, 42, 2, 2, "F");

  doc.setFont("helvetica", "bold"); doc.setFontSize(8); doc.setTextColor(GRAY);
  doc.text("BORROWER DETAILS", 20, y + 7);
  doc.text("LOAN DETAILS", 14 + boxWidth + 12, y + 7);

  const leftX = 20; const rightX = 14 + boxWidth + 12;
  const colOffset = 25; // Smaller offset for values
  kv(doc, "Name:",        loan.clientName,                          leftX, y + 16, colOffset);
  kv(doc, "National ID:", loan.nationalId,                          leftX, y + 24, colOffset);
  kv(doc, "Phone:",       loan.clientPhone,                         leftX, y + 32, colOffset);
  // Email removed if it makes it too crowded, or just keep it
  if (loan.clientEmail) kv(doc, "Email:", loan.clientEmail, leftX, y + 40, colOffset);

  kv(doc, "Type:",        loan.loanType,                            rightX, y + 16, colOffset);
  kv(doc, "Status:",      loan.status,                              rightX, y + 24, colOffset);
  kv(doc, "Start Date:",  new Date(loan.startDate).toLocaleDateString("en-KE"), rightX, y + 32, colOffset);
  kv(doc, "Due Date:",    new Date(loan.dueDate).toLocaleDateString("en-KE"), rightX, y + 40, colOffset);
  y += 50;

  // Loan terms - 2 column layout for better spacing
  doc.setFillColor(LIGHT_BG);
  doc.roundedRect(14, y, w - 28, 30, 2, 2, "F");
  const termX1 = 20;
  const termX2 = w / 2 + 10;
  const termOffset = 30;

  kv(doc, "Principal Amount:", kes(loan.principalAmount), termX1, y + 8, termOffset);
  kv(doc, "Interest Rate:",   `${loan.interestRate}% ${loan.interestType}`, termX1, y + 16, termOffset);
  kv(doc, "Total Interest:",   kes(loan.totalInterest), termX1, y + 24, termOffset);

  kv(doc, "Total Payable:",   kes(loan.totalPayable), termX2, y + 8, termOffset);
  kv(doc, "Paid Amount:",     kes(summary.totalPaid), termX2, y + 16, termOffset);
  kv(doc, "Balance Due:",     kes(summary.remainingBalance), termX2, y + 24, termOffset);
  y += 36;

  // Progress line
  doc.setFontSize(8.5); doc.setFont("helvetica", "bold"); doc.setTextColor(DARK_TEXT);
  doc.text(`Repayment Progress: ${summary.progressPercent.toFixed(1)}%`, 14, y + 4);
  doc.setFillColor("#e5e7eb");
  doc.roundedRect(14, y + 7, w - 28, 4, 1, 1, "F");
  doc.setFillColor("#22c55e");
  doc.roundedRect(14, y + 7, ((w - 28) * Math.min(100, summary.progressPercent)) / 100, 4, 1, 1, "F");
  y += 17;

  // Payment history
  autoTable(doc, {
    startY: y,
    head: [["#", "Date", "Amount (KES)", "Method", "Reference", "Balance After (KES)"]],
    body: (repayments ?? []).map((r: any, i: number) => [
      String(i + 1),
      new Date(r.date).toLocaleDateString("en-KE"),
      kes(r.amount), r.paymentMethod, r.referenceId ?? "â€”", kes(r.runningBalance),
    ]),
    foot: repayments?.length > 0 ? [["", "Total Paid", kes(summary.totalPaid), "", "", ""]] : undefined,
    footStyles: { fontStyle: "bold", fillColor: "#e5e7eb" as any },
    ...TABLE_STYLES,
  });

  // Penalties (if any)
  if (penalties?.length > 0) {
    const afterTable = (doc as any).lastAutoTable.finalY + 8;
    doc.setFont("helvetica", "bold"); doc.setFontSize(10); doc.setTextColor(DARK_TEXT);
    doc.text("Penalties & Charges", 14, afterTable);
    autoTable(doc, {
      startY: afterTable + 4,
      head: [["Date", "Type", "Amount", "Status", "Note"]],
      body: (penalties ?? []).map((p: any) => [
        new Date(p.dateApplied).toLocaleDateString("en-KE"),
        p.penaltyType, kes(p.amount), p.status, p.comment ?? "â€”",
      ]),
      ...TABLE_STYLES,
    });
  }

  addFooters(doc);
  doc.save(`loan-statement-${loan.id?.slice(-8).toUpperCase()}-${today()}.pdf`);
}

